css:
.loader {
  position: relative;
  display: inline-block;
  width: 54px;
  height: 54px;
  border-radius: 50%;
  background: var(--loader-color);
}
.loader::before,
.loader::after {
  content: "";
  position: absolute;
  inset: 0;
  border-radius: inherit;
  border: 3px solid var(--loader-color);
  animation: pulse 1.25s ease-out infinite;
}
.loader::after { animation-delay: 0.45s; }
@keyframes pulse {
  to { transform: scale(1.9); opacity: 0; }
}
